/* YallaPlays Mobile Optimizations — MIFTEH AI OS */

/* Mobile touch targets - MIFTEH AI OS patch */
button, a, [role="button"] {
  min-height: 44px;
  min-width: 44px;
}
.game-card-action {
  padding: 12px 16px;
  touch-action: manipulation;
}

/* Mobile font sizes - MIFTEH AI OS patch */
:root {
  font-size: 16px;
}
@media (max-width: 768px) {
  .game-title { font-size: 1rem; }
  .game-desc { font-size: 0.875rem; }
  body { -webkit-text-size-adjust: 100%; }
}

/* CLS prevention - MIFTEH AI OS patch */
.game-card-thumbnail {
  aspect-ratio: 4 / 3;
  width: 100%;
  background: #f0f0f0;
}
.game-hero-banner {
  min-height: 200px;
}

// Add touch event handler
const handleTouchStart = (e: React.TouchEvent) => { e.stopPropagation(); };
